20	func (r *Reconciler) createOrApplyDeployment(trustManager *v1alpha1.TrustManager, resourceLabels, resourceAnnotations map[string]string, caBundleHash string) error {
21		desired, err := r.getDeploymentObject(trustManager, resourceLabels, resourceAnnotations, caBundleHash)
22		if err != nil {
23			return err
24		}
25	
26		deploymentName := fmt.Sprintf("%s/%s", desired.GetNamespace(), desired.GetName())
27		r.log.V(4).Info("reconciling deployment resource", "name", deploymentName)
28	
29		existing := &appsv1.Deployment{}
30		exists, err := r.Exists(r.ctx, client.ObjectKeyFromObject(desired), existing)
31		if err != nil {
32			return common.FromClientError(err, "failed to check if deployment %q exists", deploymentName)
33		}
34		if exists && !deploymentModified(desired, existing) {
35			r.log.V(4).Info("deployment resource exists and is in desired state", "name", deploymentName)
36			return nil
37		}
38	
39		r.log.V(2).Info("deployment resource has been modified, updating to desired state", "name", deploymentName)
40		if err := r.Patch(r.ctx, desired, client.Apply, client.FieldOwner(fieldOwner), client.ForceOwnership); err != nil {
41			return common.FromClientError(err, "failed to apply deployment %q", deploymentName)
42		}
43	
44		r.eventRecorder.Eventf(trustManager, corev1.EventTypeNormal, "Reconciled", "deployment resource %s applied", deploymentName)
45		return nil
46	}
