48	func (r *Reconciler) getDeploymentObject(trustManager *v1alpha1.TrustManager, resourceLabels, resourceAnnotations map[string]string, caBundleHash string) (*appsv1.Deployment, error) {
49		deployment := common.DecodeObjBytes[*appsv1.Deployment](codecs, appsv1.SchemeGroupVersion, assets.MustAsset(deploymentAssetName))
50	
51		if err := validateDeploymentManifest(deployment); err != nil {
52			return nil, common.NewIrrecoverableError(err, "invalid trust-manager deployment manifest")
53		}
54	
55		common.UpdateName(deployment, trustManagerDeploymentName)
56		common.UpdateNamespace(deployment, operandNamespace)
57		common.UpdateResourceLabels(deployment, resourceLabels)
58		updateResourceAnnotations(deployment, resourceAnnotations)
59		updatePodTemplateLabels(deployment, resourceLabels)
60		updateDeploymentArgs(deployment, trustManager)
61	
62		updateServiceAccountName(deployment)
63		updateTLSSecretVolume(deployment)
64		updateDefaultCAPackageVolume(
65			deployment,
66			trustManager.Spec.TrustManagerConfig.DefaultCAPackage,
67			caBundleHash,
68		)
69	
70		if err := updateImage(deployment); err != nil {
71			return nil, common.NewIrrecoverableError(err, "failed to update trust-manager image")
72		}
73	
74		if err := updateResourceRequirements(deployment, trustManager); err != nil {
75			return nil, err
76		}
77		if err := updateAffinityRules(deployment, trustManager); err != nil {
78			return nil, err
79		}
80		if err := updatePodTolerations(deployment, trustManager); err != nil {
81			return nil, err
82		}
83		if err := updateNodeSelector(deployment, trustManager); err != nil {
84			return nil, err
85		}
86	
87		return deployment, nil
88	}
