285	const tlsVolumeName = "tls"
286	
287	func updateTLSSecretVolume(deployment *appsv1.Deployment) {
288		for i, vol := range deployment.Spec.Template.Spec.Volumes {
289			if vol.Name == tlsVolumeName && vol.Secret != nil {
290				deployment.Spec.Template.Spec.Volumes[i].Secret.SecretName = trustManagerTLSSecretName
