```go
// updateProxyEnv injects HTTP_PROXY, HTTPS_PROXY, and NO_PROXY environment
// variables into the trust-manager container when the cluster Proxy API is
// available. Values are read from the config.openshift.io/v1 Proxy/cluster
// status, which contains the effective proxy settings computed by the cluster
// network operator. On clusters without the Proxy API (MicroShift, vanilla
// Kubernetes), this is a no-op.
func (r *Reconciler) updateProxyEnv(deployment *appsv1.Deployment) error {
	if !r.proxyInformer.Applicable() {
		return nil
	}

	proxyConfig, err := (*r.proxyInformer.InformerFactory).Config().V1().Proxies().Lister().Get("cluster")
	if err != nil {
		r.log.V(2).Info("unable to read cluster proxy settings, skipping proxy env injection", "error", err)
		return nil
	}

	var proxyEnvVars []corev1.EnvVar
	if proxyConfig.Status.HTTPProxy != "" {
		proxyEnvVars = append(proxyEnvVars, corev1.EnvVar{Name: "HTTP_PROXY", Value: proxyConfig.Status.HTTPProxy})
	}
	if proxyConfig.Status.HTTPSProxy != "" {
		proxyEnvVars = append(proxyEnvVars, corev1.EnvVar{Name: "HTTPS_PROXY", Value: proxyConfig.Status.HTTPSProxy})
	}
	if proxyConfig.Status.NoProxy != "" {
		proxyEnvVars = append(proxyEnvVars, corev1.EnvVar{Name: "NO_PROXY", Value: proxyConfig.Status.NoProxy})
	}

	if len(proxyEnvVars) == 0 {
		return nil
	}

	for i, container := range deployment.Spec.Template.Spec.Containers {
		if container.Name == trustManagerContainerName {
			deployment.Spec.Template.Spec.Containers[i].Env = append(
				deployment.Spec.Template.Spec.Containers[i].Env,
				proxyEnvVars...,
			)
			break
		}
	}

	return nil
}
